#!/usr/bin/perl
use strict;
use warnings;
use PDF::API2;
use Text::CSV;

# Chemin vers le fichier PDF
my $pdf_file = "example.pdf";

# Ouvrir le PDF
my $pdf = PDF::API2->open($pdf_file);

# Créer un objet CSV pour stocker les données extraits
my $csv = Text::CSV->new({ binary => 1, auto_diag => 1 });

# Stockage des informations extraites
my %info;

# Parcourir chaque page
for my $page (1 .. $pdf->pages) {
    my $p = $pdf->page($page);
    my $text = $p->text;

    # Recherche de l'auteur
    if ($text =~ /Author: (.+)/) {
        $info{author} = $1;
    }

    # Recherche de la date
    if ($text =~ /CreationDate: (.+)/) {
        $info{date} = $1;
    }

    # Recherche des tableaux
    while (my @lines = $p->extract_text) {
        for my $line (@lines) {
            if ($line =~ /\|/) {
                $csv->string($line);
                $csv->parse($line);
                my @fields = $csv->fields();
                $info{table} //= [];
                push @{$info{table}}, { @fields };
            }
        }
    }
}

# Afficher les informations extraites
print "Auteur : ", $info{author}, "\n";
print "Date : ", $info{date}, "\n";
if (exists $info{table}) {
    print "Table:\n";
    for my $row (@{$info{table}}) {
        print join("\t", values %$row), "\n";
    }
}
